/**
 * Notification model types and interfaces.
 *
 * These types define the core notification domain: what kinds of notifications
 * exist, what channels they can be delivered through, and the payload structure
 * that flows through the notification system.
 *
 * Architecture: All notifications originate from AppEvents on the EventBus.
 * The NotificationService listens for events, builds NotificationPayloads,
 * and dispatches them through NotificationAdapter implementations.
 */

/** Supported notification types — each maps to a category of event. */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/** Delivery channels available for notifications. */
export type NotificationChannel = 'email' | 'webhook' | 'in_app';

/** Priority levels for notification delivery. */
export type NotificationPriority = 'low' | 'normal' | 'high';

/**
 * The payload dispatched to adapters for delivery.
 * Adapters receive this and translate it to channel-specific formats.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** The type of notification (determines template/formatting). */
  type: NotificationType;
  /** The delivery channel this payload targets. */
  channel: NotificationChannel;
  /** Email address or user identifier of the recipient. */
  recipient: string;
  /** Notification subject/title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Delivery priority. */
  priority: NotificationPriority;
  /** Arbitrary metadata from the originating event. */
  metadata: Record<string, string>;
  /** When the notification was created. */
  createdAt: Date;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The channel that handled delivery. */
  channel: NotificationChannel;
  /** Error message if delivery failed. */
  error?: string;
  /** Timestamp of the delivery attempt. */
  deliveredAt: Date;
}

/**
 * A stored notification record combining payload and delivery result.
 */
export interface NotificationRecord {
  /** The notification payload that was sent. */
  payload: NotificationPayload;
  /** The result of the delivery attempt. */
  result: NotificationResult;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends rather than
 * connecting to a real SMTP server. The interface is real and production-ready;
 * swap the send() internals to integrate with an actual email provider
 * (SendGrid, SES, SMTP, etc.).
 *
 * Implements NotificationAdapter so it can be registered with NotificationService.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address shown in the "From" field. */
  fromAddress: string;
  /** Display name for the sender. */
  fromName: string;
}

const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflow.example.com',
  fromName: 'TaskFlow Pro',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; timestamp: Date }> = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Send a notification as an email.
   *
   * Stub implementation: logs the email and records it in memory.
   * Replace the body of this method with real SMTP/API integration.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      this.logger.info(
        `Sending email to ${payload.recipient}: "${payload.subject}"`,
      );

      // Stub: record the email instead of actually sending it
      this.sentEmails.push({ payload, timestamp: new Date() });

      this.logger.info(
        `Email delivered to ${payload.recipient} (from: ${this.config.fromName} <${this.config.fromAddress}>)`,
      );

      return {
        success: true,
        channel: 'email',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Email delivery failed for ${payload.recipient}: ${message}`);

      return {
        success: false,
        channel: 'email',
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all emails sent through this adapter (for testing/debugging).
   */
  getSentEmails(): Array<{ payload: NotificationPayload; timestamp: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

