/**
 * Notification service — listens for AppEvents via EventBus and dispatches
 * notifications through registered NotificationAdapter implementations.
 *
 * Architecture:
 * - ALL notification triggers come through the EventBus (event-driven, no direct calls)
 * - The service translates events into NotificationPayloads
 * - Payloads are dispatched to the appropriate adapter based on channel
 * - Delivery results are emitted back onto the EventBus as notification:sent / notification:failed
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications must originate from an EventBus event
 * - Adapters are registered at construction time via dependency injection
 * - The default channel is 'email' unless overridden
 *
 * Depends on:
 * - EventBus (event system) for receiving events and emitting delivery results
 * - NotificationAdapter implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationRecord,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  /**
   * @param eventBus - The application EventBus for receiving events
   * @param adapters - Notification adapters to register, keyed by channel
   */
  constructor(
    private eventBus: EventBus,
    adapters: NotificationAdapter[] = [],
  ) {
    for (const adapter of adapters) {
      this.registerAdapter(adapter);
    }
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a channel.
   * Only one adapter per channel is supported; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all events that trigger notifications.
   * All triggers come through EventBus — no other mechanism.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  /**
   * Handle order created — send confirmation to the user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      type: 'order_confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
      metadata: {
        orderId: event.order.id,
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.dispatch({
      type: 'order_status_update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatch({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      priority: 'normal',
      metadata: {
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle user updated — notify of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    await this.dispatch({
      type: 'account_updated',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
      priority: 'low',
      metadata: {
        userId: event.user.id,
        changes: event.changes.join(','),
      },
    });
  }

  /**
   * Build a NotificationPayload and send it through the appropriate adapter.
   * Emits notification:sent or notification:failed events with the result.
   */
  private async dispatch(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata: Record<string, string>;
  }): Promise<void> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      metadata: params.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${params.channel}". ` +
        `Notification ${payload.id} stored but not delivered.`,
      );

      const failResult = {
        success: false,
        channel: params.channel,
        error: `No adapter for channel: ${params.channel}`,
        deliveredAt: new Date(),
      };
      this.records.push({ payload, result: failResult });

      await this.eventBus.emit({
        type: 'notification:failed',
        payload,
        result: failResult,
        timestamp: new Date(),
      });
      return;
    }

    const result = await adapter.send(payload);
    this.records.push({ payload, result });

    if (result.success) {
      this.logger.info(`Notification sent: ${payload.id} to ${params.recipient}`);
      await this.eventBus.emit({
        type: 'notification:sent',
        payload,
        result,
        timestamp: new Date(),
      });
    } else {
      this.logger.error(
        `Notification failed: ${payload.id} — ${result.error ?? 'unknown error'}`,
      );
      await this.eventBus.emit({
        type: 'notification:failed',
        payload,
        result,
        timestamp: new Date(),
      });
    }
  }

  /**
   * Get all notification records (payload + delivery result).
   */
  getNotificationRecords(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get all sent notifications (backward-compatible: returns payload data as flat objects).
   */
  getNotifications(): Array<{ id: string; recipient: string; subject: string; body: string; sentAt: Date }> {
    return this.records.map((r) => ({
      id: r.payload.id,
      recipient: r.payload.recipient,
      subject: r.payload.subject,
      body: r.payload.body,
      sentAt: r.payload.createdAt,
    }));
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Array<{ id: string; recipient: string; subject: string; body: string; sentAt: Date }> {
    return this.getNotifications().filter((n) => n.recipient === recipient);
  }

  /**
   * Get the total count of notifications dispatched.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all notification records (for testing).
   */
  clearNotifications(): void {
    this.records = [];
  }
}

